if ($input.all().length === 0) {
  throw new Error("No data received from the previous node.");
}

const item = $input.first();
const binaryData = item.binary || {};

const frontImage = binaryData['front'];
const sideImage = binaryData['side'];

const missing = [];
if (!frontImage) missing.push("front_view");
if (!sideImage) missing.push("side_view");
if (missing.length > 0) {
  return [{
    json: {
      error: "Missing required images",
      missing_fields: missing,
      status: "failed"
    }
  }];
}

// THIS IS THE FIX: read the actual file buffer from disk and convert to base64
const frontBuffer = await this.helpers.getBinaryDataBuffer(0, 'front');
const sideBuffer  = await this.helpers.getBinaryDataBuffer(0, 'side');

const frontBase64 = frontBuffer.toString('base64');
const sideBase64  = sideBuffer.toString('base64');

return [{
  json: {
    analysis_metadata: {
      timestamp: new Date().toISOString(),
      ready_for_ai: true
    },
    images: {
      front: {
        base64: frontBase64,
        mimeType: frontImage.mimeType,
        fileName: frontImage.fileName
      },
      side: {
        base64: sideBase64,
        mimeType: sideImage.mimeType,
        fileName: sideImage.fileName
      }
    }
  },
  binary: item.binary
}];

