// Reference each node directly by its exact name
const frontData = $('HTTP Request').first().json;
const sideData  = $('HTTP Request1').first().json;

// STEP 1: Extract text
const frontText = frontData.candidates[0].content.parts[0].text;
const sideText  = sideData.candidates[0].content.parts[0].text;

// STEP 2: Clean and parse
const clean = str => str.replace(/```json|```/g, '').trim();
let front, side;

console.log('Cleaned Front Text:', clean(frontText));
console.log('Cleaned Side Text:', clean(sideText));

try {
  front = JSON.parse(clean(frontText));
} catch(e) {
  throw new Error('Failed to parse front JSON: ' + frontText);
}
try {
  side = JSON.parse(clean(sideText));
} catch(e) {
  throw new Error('Failed to parse side JSON: ' + sideText);
}

// STEP 3: Smart scale — Gemini tells us the real cm value directly
const frontRefPx = front.reference_height_px || 0;
const sideRefPx  = side.reference_height_px  || 0;

const frontRefCm = front.reference_real_cm || 29.7;
const sideRefCm  = side.reference_real_cm  || 29.7;

let scale;
if (frontRefPx > 0) {
  scale = frontRefCm / frontRefPx;
} else if (sideRefPx > 0) {
  scale = sideRefCm / sideRefPx;
} else {
  throw new Error('No valid reference object detected in either photo. Make sure A4 paper is visible.');
}

// STEP 4: Helpers
const toWidth  = px => parseFloat((px * scale * 2).toFixed(1));
const toHeight = px => parseFloat((px * scale).toFixed(1));

// STEP 5: Measurements
const measurements = {
  height_cm:         toHeight(front.total_height_px),
  shoulder_width_cm: toWidth(front.shoulder_width_px),
  chest_circ_cm:     toWidth(front.chest_width_px),
  waist_circ_cm:     toWidth(front.waist_width_px),
  hip_circ_cm:       toWidth(front.hip_width_px),
  chest_depth_cm:    toHeight(side.chest_depth_px),
  stomach_depth_cm:  toHeight(side.stomach_depth_px),
  back_length_cm:    toHeight(side.back_length_px),
  arm_length_cm:     toHeight(side.arm_length_px),
  inseam_cm:         toHeight(side.inseam_px),
};

// STEP 6: Table
const table = [
  { measurement: 'Height',         value_cm: measurements.height_cm },
  { measurement: 'Shoulder width', value_cm: measurements.shoulder_width_cm },
  { measurement: 'Chest',          value_cm: measurements.chest_circ_cm },
  { measurement: 'Waist',          value_cm: measurements.waist_circ_cm },
  { measurement: 'Hips',           value_cm: measurements.hip_circ_cm },
  { measurement: 'Chest depth',    value_cm: measurements.chest_depth_cm },
  { measurement: 'Stomach depth',  value_cm: measurements.stomach_depth_cm },
  { measurement: 'Back length',    value_cm: measurements.back_length_cm },
  { measurement: 'Arm length',     value_cm: measurements.arm_length_cm },
  { measurement: 'Inseam',         value_cm: measurements.inseam_cm },
];

// STEP 7: Return final result
return [{
  json: {
    status: 'success',
    confidence: front.confidence,
    scale_factor: parseFloat(scale.toFixed(4)),
    notes: { front: front.notes, side: side.notes },
    measurements: measurements,
    table: table
  }
}];

// Get measurements from Node 4
const data = $input.first().json;
const m = data.measurements;
const date = new Date().toLocaleDateString('fr-FR');

// Build a clean HTML page that looks like a professional PDF report
const html = `<!DOCTYPE html>
<html>
<head>
<meta charset="UTF-8">
<style>
  body {
