    font-size: 13px;
    letter-spacing: 0.5px;
  }
  td {
    padding: 12px 16px;
    font-size: 14px;
    border-bottom: 1px solid #eee;
  }
  tr:nth-child(even) td { background: #fafafa; }
  tr:last-child td { border-bottom: none; }
  .value {
    font-weight: bold;
    font-size: 15px;
    color: #1a1a1a;
    text-align: right;
  }
  .confidence {
    display: inline-block;
    padding: 3px 10px;
    border-radius: 20px;
    font-size: 12px;
    font-weight: bold;
    background: ${data.confidence === 'high' ? '#d4edda' : data.confidence === 'medium' ? '#fff3cd' : '#f8d7da'};
    color: ${data.confidence === 'high' ? '#155724' : data.confidence === 'medium' ? '#856404' : '#721c24'};
  }
  .footer {
    margin-top: 40px;
    text-align: center;
    font-size: 11px;
    color: #aaa;
    border-top: 1px solid #eee;
    padding-top: 16px;
  }
  .notes {
    background: #fffbf0;
    border-left: 3px solid #f0ad00;
