    font-size: 12px;
    color: #555;
    margin-top: 20px;
    border-radius: 0 6px 6px 0;
  }
</style>
</head>
<body>

<div class="header">
  <h1>Body Measurements Report</h1>
  <p>Generated automatically by AI vision analysis</p>
</div>

<div class="meta">
  <span><strong>Date:</strong> ${date}</span>
  <span><strong>Confidence:</strong> <span class="confidence">${data.confidence}</span></span>
  <span><strong>Scale factor:</strong> ${data.scale_factor} cm/px</span>
</div>

<div class="section-title">Front view measurements</div>
<table>
  <tr><th>Measurement</th><th style="text-align:right">Value</th></tr>
  <tr><td>Height</td><td class="value">${m.height_cm} cm</td></tr>
  <tr><td>Shoulder width</td><td class="value">${m.shoulder_width_cm} cm</td></tr>
  <tr><td>Chest circumference</td><td class="value">${m.chest_circ_cm} cm</td></tr>
  <tr><td>Waist circumference</td><td class="value">${m.waist_circ_cm} cm</td></tr>
  <tr><td>Hip circumference</td><td class="value">${m.hip_circ_cm} cm</td></tr>
</table>

<div class="section-title">Side view measurements</div>
<table>
  <tr><th>Measurement</th><th style="text-align:right">Value</th></tr>
  <tr><td>Chest depth</td><td class="value">${m.chest_depth_cm} cm</td></tr>
  <tr><td>Stomach depth</td><td class="value">${m.stomach_depth_cm} cm</td></tr>
  <tr><td>Back length</td><td class="value">${m.back_length_cm} cm</td></tr>
  <tr><td>Arm length</td><td class="value">${m.arm_length_cm} cm</td></tr>
  <tr><td>Inseam</td><td class="value">${m.inseam_cm} cm</td></tr>
</table>

<div class="notes">
  <strong>Notes:</strong><br>
  Front: ${data.notes.front}<br>
  Side: ${data.notes.side}
</div>

<div class="footer">
  This report was generated by AI analysis. Measurements are estimates based on photo analysis.<br>
  Always verify with a professional tailor before cutting fabric.
</div>

</body>
</html>`;

// Return the HTML as a binary file that n8n can pass to the next node
const binaryData = Buffer.from(html, 'utf8').toString('base64');

return [{
  json: {
    status: 'success',
    fileName: `measurements_${Date.now()}.html`,
    measurements: m
  },
  binary: {
    report: {
      data: binaryData,
      mimeType: 'text/html',
      fileName: `measurements_${Date.now()}.html`
    }
  }
}];
